// ------------------------------------------------------------
//  Greedy – bracket assignment (C implementation)
// ------------------------------------------------------------
#include <stdio.h>
#include <string.h>
#include <stdbool.h>

#define MAXN 2005
#define ALPH 26

int N;
char S[MAXN];
int freq[ALPH];
int order[ALPH]; // indices of characters that actually appear
int distinctCnt;
int assign[ALPH]; // 1 = '(', -1 = ')', 0 = unassigned
int need; // how many '(' still required

bool verify(void) {
    int bal = 0;
    for (int i = 0; i < N; ++i) {
        int c = S[i] - 'a';
        if (assign[c] == 1) ++bal; else --bal;
        if (bal < 0) return false;
    }
    return bal == 0;
}

bool dfs(int idx, int remainingNeed) {
    if (idx == distinctCnt) {
        if (remainingNeed != 0) return false;
        return verify();
    }
    int ch = order[idx];
    int f = freq[ch];
    // try '(' if possible
    if (remainingNeed >= f) {
        assign[ch] = 1;
        if (dfs(idx + 1, remainingNeed - f)) return true;
    }
    // try ')'
    assign[ch] = -1;
    if (dfs(idx + 1, remainingNeed)) return true;
    assign[ch] = 0;
    return false;
}

int main() {
    int T; scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        scanf("%s", S);
        if (N % 2 == 1) {
            printf("NO\n");
            continue;
        }
        memset(freq, 0, sizeof(freq));
        for (int i = 0; i < N; ++i) freq[S[i] - 'a']++;
        distinctCnt = 0;
        for (int i = 0; i < ALPH; ++i) if (freq[i]) order[distinctCnt++] = i;
        // sort characters by decreasing frequency to prune faster
        for (int i = 0; i < distinctCnt; ++i) {
            for (int j = i + 1; j < distinctCnt; ++j) {
                if (freq[order[i]] < freq[order[j]]) {
                    int tmp = order[i]; order[i] = order[j]; order[j] = tmp;
                }
            }
        }
        memset(assign, 0, sizeof(assign));
        need = N / 2;
        bool ok = dfs(0, need);
        if (!ok) {
            printf("NO\n");
        } else {
            printf("YES\n");
            for (int i = 0; i < N; ++i) {
                putchar(assign[S[i] - 'a'] == 1 ? '(' : ')');
            }
            putchar('\n');
        }
    }
    return 0;
}

