// ------------------------------------------------------------
//  Greedy – bracket assignment (C++17 implementation)
// ------------------------------------------------------------
#include <bits/stdc++.h>
using namespace std;

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;cin>>T;
    while(T--){
        int N;cin>>N;string S;cin>>S;
        if(N%2){cout<<"NO\n";continue;}
        vector<int> freq(26,0);
        for(char ch:S) freq[ch-'a']++;
        vector<int> chars;
        for(int i=0;i<26;i++) if(freq[i]) chars.push_back(i);
        // sort by decreasing frequency for better pruning
        sort(chars.begin(), chars.end(), [&](int a,int b){return freq[a]>freq[b];});
        vector<int> assign(26,0); // 1 '(' , -1 ')'
        function<bool(int,int)> dfs = [&](int idx,int need){
            if(idx==(int)chars.size()){
                if(need!=0) return false;
                int bal=0;
                for(char ch:S){
                    bal+= (assign[ch-'a']==1)?1:-1;
                    if(bal<0) return false;
                }
                return bal==0;
            }
            int c=chars[idx];
            int f=freq[c];
            // try '(' if enough need left
            if(need>=f){
                assign[c]=1;
                if(dfs(idx+1,need-f)) return true;
            }
            // try ')'
            assign[c]=-1;
            if(dfs(idx+1,need)) return true;
            assign[c]=0;
            return false;
        };
        bool ok=dfs(0,N/2);
        if(!ok){cout<<"NO\n";}
        else{
            cout<<"YES\n";
            for(char ch:S) cout<<(assign[ch-'a']==1?'(' : ')');
            cout<<"\n";
        }
    }
    return 0;
}

